   222→    <div class="main-grid">
   223→      <div class="left-col">
   224→        <div>
   225→          <div class="section-title">Objects (10)</div>
   226→          <div id="objects-grid"></div>
   227→        </div>
   228→        <div>
   229→          <div class="section-title">Characters</div>
   230→          <div id="characters-grid"></div>
   231→        </div>
   232→      </div>
   233→      <div id="log-section">
   234→        <div class="section-title">Event Log</div>
   235→        <div id="event-log"><div style="color:#555;padding:4px 0">No events yet.</div></div>
   236→      </div>
   237→    </div>
   238→  </div>
