/* ── Object cards ── */
#objects-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(210px, 1fr));
  gap: 8px;
}

.object-card {
  background: #222240;
  border: 1px solid #333;
  border-radius: 6px;
  padding: 10px 14px;
}
.object-card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 4px;
}
.object-name { font-weight: bold; color: #c8d4e8; text-transform: capitalize; }

.state-badge {
  padding: 2px 8px;
  border-radius: 3px;
  font-size: 11px;
}
.state-badge.idle   { background: #1a2a1a; color: #77cc77; border: 1px solid #2a4a2a; }
.state-badge.active { background: #2a2a1a; color: #cccc77; border: 1px solid #4a4a2a; }
.state-badge.done   { background: #1a1a2a; color: #88aacc; border: 1px solid #2a3a5a; }
.state-badge.other  { background: #2a1a2a; color: #cc88cc; border: 1px solid #4a2a4a; }

.position-hint { font-size: 10px; color: #555; }

.slot-info {
  font-size: 10px;
  margin-top: 4px;
  display: flex;
  align-items: center;
  gap: 5px;
}
.slot-pips { display: flex; gap: 2px; }
.slot-pip {
  width: 8px; height: 8px;
  border-radius: 2px;
  border: 1px solid #444;
}
.slot-pip.occupied  { background: #cc7755; border-color: #aa5533; }
.slot-pip.reserved  { background: #8888aa; border-color: #666688; }
.slot-pip.available { background: #2a2a3a; border-color: #444; }
.slot-label { color: #666; }
.slot-label.full { color: #cc7755; }

.timer-bar {
  height: 4px;
  background: #2a2a40;
  border-radius: 2px;
  margin-top: 6px;
  overflow: hidden;
}
