function updateObjectCard(obj) {
  const badge      = document.getElementById(`badge-${obj.id}`);
  const timerBar   = document.getElementById(`timerbar-${obj.id}`);
  const timerFill  = document.getElementById(`timerfill-${obj.id}`);
  const timerText  = document.getElementById(`timertext-${obj.id}`);
  const intDiv     = document.getElementById(`int-${obj.id}`);
  if (!badge) return;

  const prevState = badge.dataset.state;
  const stateChanged = prevState !== obj.state;

  if (stateChanged) {
    badge.textContent = obj.state;
    badge.className = `state-badge ${badgeClass(obj.state)}`;
    badge.dataset.state = obj.state;

    // Rebuild interaction buttons on state change
    const stateDef = obj.states[obj.state];
    const actions = Object.keys(stateDef?.transitions || {});
    intDiv.innerHTML = actions.map(a =>
      `<button onclick="window._dbInteract('${obj.id}','${a}')">${a}</button>`
    ).join('');
  }

  // Slot occupancy (update every frame)
  const slotDiv = document.getElementById(`slots-${obj.id}`);
  if (slotDiv) {
    const si = obj.getSlotInfo();
    const pips = [];
    for (let i = 0; i < si.capacity; i++) {
      let cls = 'available';
      if (i < si.occupied)                      cls = 'occupied';
      else if (i < si.occupied + si.reserved)   cls = 'reserved';
      pips.push(`<div class="slot-pip ${cls}" title="${cls}"></div>`);
    }
    const labelCls = si.available === 0 ? 'slot-label full' : 'slot-label';
    const labelTxt = si.available === 0 ? 'full' : `${si.available}/${si.capacity} free`;
    slotDiv.innerHTML = `<div class="slot-pips">${pips.join('')}</div><span class="${labelCls}">${labelTxt}</span>`;
  }

  // Timer bar (update every frame regardless of state change)
  const stateDef = obj.states[obj.state];
  const hasTimer = !!(stateDef?.auto_next && obj.autoTimer > 0);
  if (hasTimer) {
    const totalMs = stateDef.auto_next.after * 1000;
    const pct = Math.max(0, Math.min(100, (1 - obj.autoTimer / totalMs) * 100));
    timerBar.style.display = '';
    timerFill.style.width  = `${pct.toFixed(1)}%`;
    timerText.style.display = '';

