// Verify slot logic inline (no imports needed)
class ObjectInstance {
  constructor(capacity) {
    this.capacity = capacity;
    this._reservations = new Set();
    this._occupants = new Set();
  }
  isFull()         { return this._reservations.size + this._occupants.size >= this.capacity; }
  reserve(name)    { if (this.isFull()) return false; this._reservations.add(name); return true; }
  arrive(name)     { this._reservations.delete(name); this._occupants.add(name); }
  release(name)    { this._reservations.delete(name); this._occupants.delete(name); }
  clearSlots()     { this._reservations.clear(); this._occupants.clear(); }
  getSlotInfo()    { return { capacity: this.capacity, reserved: this._reservations.size, occupied: this._occupants.size, available: this.capacity - this._reservations.size - this._occupants.size }; }
}

// Test capacity-1 object
const teaSet = new ObjectInstance(1);
console.assert(teaSet.reserve('Maple') === true, 'Maple can reserve empty object');
console.assert(teaSet.reserve('Sol')   === false, 'Sol cannot reserve full object');
console.assert(teaSet.isFull()         === true,  'Object is full after 1 reservation');
teaSet.arrive('Maple');
console.assert(teaSet._reservations.size === 0, 'Reservation cleared on arrive');
console.assert(teaSet._occupants.size   === 1, 'Occupant added on arrive');
teaSet.release('Maple');
console.assert(teaSet.isFull()           === false, 'Object free after release');
console.assert(teaSet.reserve('Sol')     === true,  'Sol can reserve after release');

// Test capacity-2 object
const kotatsu = new ObjectInstance(2);
console.assert(kotatsu.reserve('Maple') === true, 'First reservation OK');
console.assert(kotatsu.reserve('Sol')   === true, 'Second reservation OK');
console.assert(kotatsu.reserve('Nyx')   === false,'Third reservation blocked');
kotatsu.arrive('Maple'); kotatsu.arrive('Sol');
kotatsu.release('Maple');
console.assert(kotatsu.reserve('Nyx')   === true, 'Slot opens after release');

// Test getSlotInfo
const info = kotatsu.getSlotInfo();
console.assert(info.capacity === 2, 'Capacity correct');
console.assert(info.occupied === 1, 'Occupied count correct');
console.assert(info.reserved === 1, 'Reserved count correct');
console.assert(info.available === 0, 'Available count correct');

console.log('All slot system tests passed!');
"
